import { triggerNamespace, listItemClassName } from '../constants';

/**
 * @typedef {Object} MenuOffsetProp
 * @prop {boolean} centeredMenu
 * @prop {import('react').RefObject<HTMLDivElement | null>} mainContainerRef
 */

/** @param {HTMLUListElement} menu */
const getItemToFocus = (menu) => {
  const optionsList = Array.prototype.slice.call(menu.querySelectorAll(`.${listItemClassName}`));

  if (optionsList.length) {
    // Search last navigated option
    let focusableOption = optionsList.find(option =>
      option.tabIndex === 0,
    );

    // Search selected option
    if (!focusableOption) {
      focusableOption = optionsList.find(option =>
        option.className.indexOf(`.${listItemClassName}--selected`) !== -1,
      );
    }

    // default to first option
    if (!focusableOption) {
      [focusableOption] = optionsList;
    }

    return focusableOption;
  }

  return null;
};

const TRIGGER_MARGIN = 2;

/**
 * Fuction to calculate the position of the menu when centered over the trigger
 * @param {MenuOffsetProp} prop
 */
const getMenuOffset = ({ centeredMenu, mainContainerRef }) => {
  if (!centeredMenu) {
    return { offset: undefined, calculated: true };
  }

  const main = mainContainerRef.current;
  const floatingMenu = main?.querySelector('ul');
  const scrollableContainer = main?.querySelector('.andes-popper');
  const trigger = main?.querySelector(`.${triggerNamespace}`);

  if (floatingMenu && trigger) {
    const itemToCenter = getItemToFocus(floatingMenu);

    if (itemToCenter) {
      const itemHeight = itemToCenter.offsetHeight;

      /* Calculates the position of the element related to the scrollable parent container */
      const distance = itemToCenter.offsetTop - /** @type {Element} */(scrollableContainer).scrollTop;

      /* Positions the menu to center the selected element on top of the trigger */
      const offset = -itemHeight - distance - TRIGGER_MARGIN;

      return { offset, calculated: true };
    }
  }

  return { offset: undefined, calculated: false };
};

export default getMenuOffset;
