import { useEffect, useMemo, useState } from 'react';
import { useAndesContext } from '@andes/context';
import { MENU_ALIGNMENT_CENTER, MENU_BOTTOM_OFFSET_Y } from '../constants/layout';
import getMenuOffset from '../utils/getMenuOffset';
import getItemsPrimary from '../utils/getItemsPrimary';
import getTriggerDisplayValues from '../utils/getTriggerDisplayValues';


/**
 * @typedef {Object} SearchConfigProps
 * @prop {import('../utils/computeSearchProps').ComputeSearchProps} [searchConfig]
 */

/**
 * @param {import('react').RefObject<HTMLDivElement | null>} mainContainerRef
 * @param {import('../..').DropdownProps & SearchConfigProps} props
 */
const useDropdown = (mainContainerRef, {
  children,
  defaultValue,
  disabled,
  helper,
  label,
  menuAlignment,
  modifier,
  multiple,
  onChange,
  onClose,
  onOpen,
  open,
  placeholder,
  searchConfig,
  srLabel,
  value,
  ...other
}) => {
  // eslint-disable-next-line react-hooks/exhaustive-deps
  const isUncontrolled = useMemo(() => value === undefined, []);

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const isOpenUncontrolled = useMemo(() => open === undefined, []);

  const centeredMenu = useMemo(() => {
    if (multiple || searchConfig) return false;

    return menuAlignment === MENU_ALIGNMENT_CENTER;
  }, [menuAlignment, multiple, searchConfig]);

  const itemsPrimaryReference = useMemo(() => {
    if (!children) return {};

    return getItemsPrimary({ children });
  }, [children]);

  const { device } = useAndesContext();

  const isMobile = device?.mobile;

  const [currentValues, setCurrentValues] = useState(value || defaultValue);
  const [currentDisplayValues, setCurrentDisplayValues] = useState(
    getTriggerDisplayValues({ values: currentValues, multiple, itemsPrimaryReference }),
  );
  const [isMenuVisible, setIsMenuVisible] = useState(false);
  const offsetInitialValue = /** @type {number | undefined} */ (centeredMenu ? 0 : MENU_BOTTOM_OFFSET_Y);
  const [menuOffset, setMenuOffset] = useState(offsetInitialValue);
  const [menuOffsetCalculated, setMenuOffsetCalculated] = useState(false);
  const [placement, setPlacement] = useState(/** @type {string | undefined} */(undefined));

  /** @type {import('@andes/floating-menu').FloatingMenuProps['onChange']} */
  const handleOnChange = (event, values) => {
    if (isUncontrolled) {
      setCurrentValues(values);
      setCurrentDisplayValues(getTriggerDisplayValues({ values, multiple, itemsPrimaryReference }));
    }

    if (typeof onChange === 'function') {
      // Don't modify event.target.value if the event comes from an input element
      // (e.g., searchbox) to prevent unwanted value changes in the input
      const isInputEvent = event.target instanceof HTMLInputElement;

      if (!isInputEvent) {
        // @ts-expect-error
        // value is not a valid prop for HTMLDivElement, we are adding them to the event
        event.target.value = values;
      }

      onChange(event, values);
    }
  };

  /** @type {import('@andes/floating-menu').FloatingMenuProps['onOpen']} */
  const handleOpen = (event) => {
    if (isOpenUncontrolled) {
      setIsMenuVisible(true);
      setTimeout(() => {
        const { offset, calculated } = getMenuOffset({ centeredMenu, mainContainerRef });
        setMenuOffset(offset);
        setMenuOffsetCalculated(calculated);
      }, 0);
    }

    if (typeof onOpen === 'function') onOpen(event);
  };

  /** @type {import('@andes/floating-menu').FloatingMenuProps['onClose']} */
  const handleClose = () => {
    if (isOpenUncontrolled) {
      setIsMenuVisible(false);

      if (centeredMenu) {
        setMenuOffset(0);
        setMenuOffsetCalculated(false);
      }
    }

    if (typeof onClose === 'function') onClose();
  };

  useEffect(() => {
    if (!isUncontrolled) {
      setCurrentValues(value);
      setCurrentDisplayValues(getTriggerDisplayValues({ values: value, multiple, itemsPrimaryReference }));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [value]);

  useEffect(() => {
    if (!isOpenUncontrolled) {
      if (open) {
        setIsMenuVisible(true);

        setTimeout(() => {
          const { offset, calculated } = getMenuOffset({ centeredMenu, mainContainerRef });
          setMenuOffset(offset);
          setMenuOffsetCalculated(calculated);
        }, 0);
      } else {
        setIsMenuVisible(false);

        if (centeredMenu) {
          setMenuOffset(0);
          setMenuOffsetCalculated(false);
        }
      }
    }
  }, [open, isOpenUncontrolled, centeredMenu, mainContainerRef]);

  const getValuesAsArray = () => {
    if (Array.isArray(currentValues)) return currentValues;

    if ((typeof currentValues === 'string' && !!currentValues) || typeof currentValues === 'number') return [currentValues];

    return [];
  };
  const getPopperOptions = () => {
    if (menuAlignment === 'center' || (isMobile && searchConfig)) {
      const fallbackPlacements = isMobile && searchConfig ? ['top', 'bottom'] : [];

      return {
        modifiers: [{
          name: 'flip',
          options: {
            fallbackPlacements,
          },
        }],
      };
    }

    return {};
  };

  const menuProps = {
    ...other,
    menuOffsetCalculated,
    menuOffsetY: menuOffset,
    onChange: handleOnChange,
    onClose: handleClose,
    onOpen: handleOpen,
    popperOptions: getPopperOptions(),
    onMount: (/** @type {import('tippy.js').Instance} */ instance) =>
      setPlacement(instance.popperInstance?.state?.placement),
    placement: placement || 'bottom',
  };

  return {
    currentDisplayValues,
    currentValues: getValuesAsArray(),
    isMenuVisible,
    menuProps,
  };
};

export default useDropdown;
