import { Children } from 'react';
import warning from '@andes/common/build/utils/warning';
import { WARNING_DUPLICATED_VALUE } from '../constants/warnings';
import { DROPDOWN_ITEM_DISPLAY_NAME, DROPDOWN_GROUP_DISPLAY_NAME } from '../constants/components';

/**
 * @typedef {Object} ItemsPrimaryProps
 * @prop {import('react').ReactElement | import('react').ReactElement[]} children
 */

/** @param {ItemsPrimaryProps} props */
const getItemsPrimary = ({ children }) => {
  const firstOption = Array.isArray(children) ? children[0] : children;
  // @ts-expect-error TS doesn't recognize displayName as a valid property
  const firstOptionType = firstOption?.type?.displayName;
  const reference = /** @type {Record<string, { isSlotted: Boolean; content: string }>} */({});

  /** @param {import('react').ReactElement} item */
  const setPrimaryReference = item => {
    const {
      children: itemChildren,
      title,
      value: itemValue,
    } = item.props;
    warning(!reference[itemValue], WARNING_DUPLICATED_VALUE.replace('{0}', itemValue));

    const defaultContent = !!title;
    const isSlotted = itemChildren && !defaultContent;

    reference[itemValue] = {
      isSlotted,
      content: title,
    };
  };

  if (firstOptionType === DROPDOWN_ITEM_DISPLAY_NAME) {
    Children.forEach(children, setPrimaryReference);
  }

  if (firstOptionType === DROPDOWN_GROUP_DISPLAY_NAME) {
    Children.forEach(children, group => {
      Children.forEach(group.props.children, setPrimaryReference);
    });
  }

  return reference;
};

export default getItemsPrimary;
