import React from 'react';
import PropTypes from 'prop-types';
import { FloatingMenuGroup } from '@andes/floating-menu';
import { DROPDOWN_GROUP_DISPLAY_NAME } from '../constants/components';

/** @type {typeof import('../..').DropdownGroup} */
const DropdownGroup = ({ children, ...props }) => (
  <FloatingMenuGroup {...props}>
    {children}
  </FloatingMenuGroup>
);

DropdownGroup.displayName = DROPDOWN_GROUP_DISPLAY_NAME;

DropdownGroup.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element.isRequired, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
};

export default DropdownGroup;
