import React from 'react';
import PropTypes from 'prop-types';
import { FloatingMenuItem } from '@andes/floating-menu';
import { DROPDOWN_ITEM_DISPLAY_NAME } from '../constants/components';

/** @type {typeof import('../..').DropdownItem} */
const DropdownItem = (props) => {
  const {
    children,
    description,
    rightContent,
    title,
  } = props;

  return (
    <FloatingMenuItem
      {...props}
      title={title}
      description={description}
      rightContent={rightContent}
    >
      {children}
    </FloatingMenuItem>
  );
};

DropdownItem.displayName = DROPDOWN_ITEM_DISPLAY_NAME;

DropdownItem.propTypes = {
  children: PropTypes.node,
  description: PropTypes.oneOfType([PropTypes.node, PropTypes.string]),
  disabled: PropTypes.bool,
  rightContent: PropTypes.oneOfType([PropTypes.node, PropTypes.string]),
  title: PropTypes.string,
  value: PropTypes.string.isRequired,
};

export default DropdownItem;
