import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import { MODIFIER_ERROR, MODIFIER_READONLY } from '../constants/layout';


/**
 * @param {'form' | 'standalone' | 'native'} dropdownType
 * @param {Pick<import('../..').DropdownFormProps, "disabled" | "modifier">} state
 * @param {string} [dataAttributesComponent]
 */
export const getDataAttributes = (dropdownType, { disabled, modifier }, dataAttributesComponent = 'dropdown') => ({
  container: {
    [`data-andes-${dataAttributesComponent}`]: true,
    'data-andes-dropdown-type': dropdownType,
    ...computeDataAndesState({
      disabled,
      error: modifier === MODIFIER_ERROR,
      readonly: modifier === MODIFIER_READONLY,
    }),
  },
  label: { [`data-andes-${dataAttributesComponent}-label`]: true },
  placeholder: { [`data-andes-${dataAttributesComponent}-placeholder`]: true },
  trigger: { [`data-andes-${dataAttributesComponent}-trigger`]: true },
  triggerContent: { [`data-andes-${dataAttributesComponent}-trigger-content`]: true },
  value: { [`data-andes-${dataAttributesComponent}-value`]: true },
  chevron: { [`data-andes-${dataAttributesComponent}-chevron`]: true },
  helper: { [`data-andes-${dataAttributesComponent}-helper`]: true },
});
