import React, { Children, cloneElement } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useId } from '@andes/context';
import { Helper } from '@andes/form';
import ChevronDown20 from '@andes/icons/ChevronDown20';
import { MODIFIER_ERROR } from '../constants/layout';
import computeValueType from '../utils/computeValueType';
import { DROPDOWN_NATIVE_DISPLAY_NAME } from '../constants/components';
import { namespace, formNamespace } from '../constants';
import { useThemeContext } from '@andes/themes';
import { getDataAttributes } from '../utils/getDataAttributes';

/** @type {typeof import('../..').DropdownNative} */
const DropdownNative = ({
  children,
  className,
  defaultValue: defaultValueProp,
  disabled,
  helper,
  id,
  label,
  modifier,
  onChange,
  value: valueProp,
  ref,
  ...props
}) => {
  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const dataAttributes = getDataAttributes('native', { disabled, modifier });

  const { value, defaultValue } = computeValueType({ valueProp, defaultValueProp });

  /** @param {React.ChangeEvent<HTMLSelectElement>} event */
  const handleOnChange = (event) => {
    const newValue = event.target.value;

    if (typeof onChange === 'function') onChange(event, newValue);
  };

  const containerClassNames = classNames(
    namespace,
    className,
    `${formNamespace}`,
    `${namespace}--form-native`,
    `${namespace}--default`, {
      [`${namespace}--error`]: modifier === MODIFIER_ERROR,
      [`${namespace}--disabled`]: disabled,
    },
    getThemedComponentClasses?.('dropdown'),
  );

  const triggerClassNames = classNames(`${namespace}__trigger`, `${namespace}__trigger-reset`);

  const options = Children.map(children, (/** @type {React.ReactElement} */ item, index) => cloneElement(item, { index, type: 'native' }));

  return (
    <div
      id={componentId}
      className={containerClassNames}
      ref={ref}
      {...themeHash}
      {...dataAttributes?.container}
    >
      {/* eslint-disable-next-line jsx-a11y/label-has-associated-control */}
      <label>
        {label && (
          <span
            className={`${namespace}__label`}
            {...dataAttributes?.label}
          >
            {label}
          </span>
        )}
        <div className={`${namespace}__trigger-wrapper`}>
          {/* eslint-disable-next-line jsx-a11y/no-onchange */}
          <select
            aria-describedby={helper ? `${id}-helper` : undefined}
            aria-invalid={modifier === MODIFIER_ERROR}
            className={triggerClassNames}
            defaultValue={defaultValue}
            disabled={disabled}
            id={id}
            key="andes-select"
            onChange={handleOnChange}
            value={value}
            {...props}
            {...dataAttributes?.trigger}
          >
            {options}
          </select>
          <div className={`${namespace}__chevron`} aria-hidden {...dataAttributes?.chevron}>
            <ChevronDown20 color="currentColor" />
          </div>
        </div>
      </label>
      {(helper && !disabled) && (
        <Helper
          // @ts-expect-error: Internal prop
          andesDataAttributes={dataAttributes?.helper}
          className={`${namespace}__helper`}
          id={`${id}-helper`}
          modifier={modifier === MODIFIER_ERROR ? MODIFIER_ERROR : undefined}
        >
          {helper}
        </Helper>
      )}
    </div>
  );
};

DropdownNative.displayName = DROPDOWN_NATIVE_DISPLAY_NAME;

DropdownNative.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element.isRequired, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
  className: PropTypes.string,
  defaultValue: PropTypes.string,
  disabled: PropTypes.bool,
  helper: PropTypes.node,
  id: PropTypes.string,
  label: PropTypes.string.isRequired,
  modifier: PropTypes.oneOf([MODIFIER_ERROR]),
  onChange: PropTypes.func,
  value: PropTypes.string,
};

export default DropdownNative;
