/** @typedef {import('../../../floating-menu/lib/utils/computeSearchProps').ComputeSearchProps} ComputeSearchProps */

/** @param {ComputeSearchProps} props */
const computeSearchProps = ({
  search: searchProps,
}) => {
  if (!searchProps) return undefined;

  if (typeof searchProps === 'boolean') {
    return { search: true };
  }

  return { ...searchProps, search: true };
};

export default computeSearchProps;
