/* eslint-disable no-console */
import React, { useRef, useState, useEffect } from 'react';
import classNames from 'classnames';
import PropTypes from 'prop-types';
import { FloatingMenu } from '@andes/floating-menu';
import { useId } from '@andes/context';
import {
  SIZE_LARGE,
  MENU_STANDALONE_OFFSET_X,
} from '../constants/layout';
import useDropdown from '../hooks/useDropdown';
import { WARNING_LABEL } from '../constants/warnings';
import computeSearchProps from '../utils/computeSearchProps';
import computeValueType from '../utils/computeValueType';
import { namespace, triggerNamespace } from '../constants';
import ChevronDown12 from '@andes/icons/ChevronDown12';
import { useThemeContext } from '@andes/themes';
import { getDataAttributes } from '../utils/getDataAttributes';
import warning from '@andes/common/build/utils/warning';

/** @type {typeof import('../..').DropdownStandalone} */
const DropdownStandalone = ({ ref, ...props }) => {
  const {
    allowUnselect = false,
    children,
    className,
    defaultOpen,
    defaultValue: defaultValueProp,
    disabled = false,
    id: idProp,
    label = '',
    menuAlignment = 'center',
    menuMaxHeight,
    multiple = false,
    open,
    search = false,
    size = SIZE_LARGE,
    srLabel,
    value: valueProp,
    renderCustomTrigger,
  } = props;

  const id = useId(idProp);
  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const dataAttributes = getDataAttributes('standalone', { disabled });

  warning(srLabel || label, WARNING_LABEL);

  /** @type {React.RefObject<HTMLDivElement | null>} */
  const ownContainerRef = useRef(null);

  /** @type {React.RefObject<HTMLDivElement | null>} */
  const containerRef = /** @type {React.RefObject<HTMLDivElement>} */(ref) || ownContainerRef;

  const searchConfig = computeSearchProps({ search });
  const { value, defaultValue } = computeValueType({ valueProp, defaultValueProp });

  const defaultProps = { disabled, menuAlignment, multiple, search, size };

  const {
    menuProps,
    isMenuVisible,
    currentDisplayValues,
    currentValues,
  } = useDropdown(containerRef, { ...props, ...defaultProps, id, searchConfig, value, defaultValue });

  /**
   * @param {(content: React.ReactNode) => void} [updateTriggerContent]
   * @returns {React.ReactNode}
   */
  const getTriggerContent = (updateTriggerContent) => {
    let newTriggerContent = /** @type {React.ReactNode} */('');

    if (typeof currentDisplayValues === 'string') {
      newTriggerContent = currentDisplayValues;
    } else if (Array.isArray(currentDisplayValues) && currentDisplayValues.length === 1) {
      [newTriggerContent] = currentDisplayValues;
    }

    if (typeof renderCustomTrigger === 'function') {
      newTriggerContent = renderCustomTrigger(currentDisplayValues, currentValues);
    }

    if (typeof updateTriggerContent === 'function') updateTriggerContent(newTriggerContent);
    return newTriggerContent;
  };

  const [triggerContent, setTriggerContent] = useState(getTriggerContent());

  useEffect(() => {
    getTriggerContent(setTriggerContent);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentDisplayValues]);

  const getMenuWidth = () => {
    const main = containerRef.current;
    const trigger = main?.getElementsByClassName(triggerNamespace)[0];

    if (trigger) {
      return ({
        width: 'auto',
        minWidth: trigger.clientWidth + -MENU_STANDALONE_OFFSET_X,
      });
    }

    return undefined;
  };

  const containerClassNames = classNames(namespace, `${namespace}--standalone`, className, {
    [`${namespace}--open`]: isMenuVisible,
    [`${namespace}--${size}`]: size,
    [`${namespace}--disabled`]: disabled,
    [`${namespace}--bottom`]: menuAlignment === 'bottom' || searchConfig,
  }, getThemedComponentClasses?.('dropdown'));

  const {
    menuOffsetCalculated,
    menuOffsetY,
    ...other
  } = menuProps;

  const labelledBy = [
    label && `${id}-label`,
    triggerContent && `${id}-display-values`,
  ].filter(Boolean).join(' ') || undefined;

  const trigger = (
    <button
      aria-label={srLabel}
      aria-labelledby={!srLabel ? labelledBy : undefined}
      className={triggerNamespace}
      disabled={disabled}
      type="button"
      id={`${id}-trigger`}
      {...dataAttributes?.trigger}
    >
      {label && (
        <span
          className={`${triggerContent ? 'andes-visually-hidden' : `${namespace}__display-values`}`}
          id={`${id}-label`}
          {...dataAttributes?.label}
        >
          {label}
        </span>
      )}
      {triggerContent && (
        <span
          className={`${namespace}__display-values`}
          id={`${id}-display-values`}
          {...dataAttributes?.value}
        >
          {triggerContent}
        </span>
      )}
      <span className={`${namespace}__arrow`} aria-hidden {...dataAttributes?.chevron}>
        <ChevronDown12 color="currentColor" />
      </span>
    </button>
  );

  return (
    <div
      id={menuProps.id}
      className={containerClassNames}
      ref={containerRef}
      {...themeHash}
      {...dataAttributes.container}
    >
      <FloatingMenu
        {...other}
        {...getMenuWidth()}
        search={searchConfig}
        srLabel={srLabel || label}
        allowUnselect={allowUnselect}
        className={menuOffsetCalculated ? 'andes-floating-menu--show' : ''}
        defaultOpen={defaultOpen}
        defaultValue={defaultValue}
        id={`${menuProps.id}-menu`}
        menuMaxHeight={menuMaxHeight}
        multiple={multiple}
        // @ts-expect-error
        // Offset prop doesn't exist in FloatingMenu, it's a popper prop
        offset={[MENU_STANDALONE_OFFSET_X, menuOffsetY]}
        open={open}
        placement="bottom-start"
        trigger={trigger}
        type="select"
        value={value}
      >
        {children}
      </FloatingMenu>
    </div>
  );
};

DropdownStandalone.propTypes = {
  allowUnselect: PropTypes.bool,
  children: PropTypes.oneOfType([PropTypes.element.isRequired, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
  className: PropTypes.string,
  defaultOpen: PropTypes.bool,
  defaultValue: PropTypes.oneOfType([PropTypes.string, PropTypes.arrayOf(PropTypes.string.isRequired)]),
  disabled: PropTypes.bool,
  id: PropTypes.string,
  label: PropTypes.string,
  menuAlignment: PropTypes.oneOf(['bottom', 'center']),
  menuMaxHeight: PropTypes.number,
  multiple: PropTypes.bool,
  onChange: PropTypes.func,
  onClose: PropTypes.func,
  onOpen: PropTypes.func,
  open: PropTypes.bool,
  renderCustomTrigger: PropTypes.func,
  search: PropTypes.oneOfType([PropTypes.bool, PropTypes.shape({
    defaultValue: PropTypes.string,
    placeholder: PropTypes.string,
    onChange: PropTypes.func,
    filterCondition: PropTypes.func,
  })]),
  size: PropTypes.oneOf(['small', 'medium', 'large']),
  srLabel: PropTypes.string,
  value: PropTypes.oneOfType([PropTypes.string.isRequired, PropTypes.arrayOf(PropTypes.string.isRequired)]),
};

export default DropdownStandalone;
