import React from 'react';
import classNames from 'classnames';
import PropTypes from 'prop-types';
import { useAndesContext, useId } from '@andes/context';
import includes from '@andes/common/build/utils/includes';
import { PillIcon } from '@andes/badge';
import { useThemeContext } from '@andes/themes';
import { namespace, MODIFIER, COLOR } from '../constants';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import enTranslations from '../../translations/en/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';

/** @typedef {import('../..').HelperProps} HelperPublicProps */

/**
 * @typedef {Object} HelperInternalProps
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/** @type {React.FunctionComponent<HelperPublicProps & HelperInternalProps>} */
const Helper = (props) => {
  const { andesDataAttributes = {}, children, className, id, modifier, ...otherProps } = props;
  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  const { i18n } = useAndesContext(
    '@andes/form',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations },
  );

  const showBadgeIcon = includes(MODIFIER, modifier || '');

  const helperClassName = classNames(namespace, className, getThemedComponentClasses?.('helper'), {
    [`${namespace}--${modifier}`]: modifier,
  });

  return (
    <div
      className={helperClassName}
      id={componentId}
      {...otherProps}
      {...themeHash}
      {...andesDataAttributes}
      data-andes-helper
      {...computeDataAndesState({
        error: modifier === 'error',
        caution: modifier === 'caution',
      })}
    >
      {showBadgeIcon && (
        <div className={`${namespace}__badge`} data-andes-helper-badge>
          <PillIcon
            color={modifier ? COLOR[modifier] : undefined}
            size="xsmall"
            srLabel={i18n.pgettext(namespace, modifier === 'error' ? 'Error' : 'Precaución')}
          />
        </div>
      )}
      <span className={`${namespace}__label`} data-andes-helper-label>{children}</span>
    </div>
  );
};

Helper.displayName = 'Helper';

Helper.propTypes = {
  andesDataAttributes: PropTypes.shape({}),
  children: PropTypes.node.isRequired,
  className: PropTypes.string,
  id: PropTypes.string,
  modifier: PropTypes.oneOf(MODIFIER),
};

export default Helper;
