import React, { useEffect, useRef, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useId } from '@andes/context';
import { FloatingMenu } from '@andes/floating-menu';
import { Helper } from '@andes/form';
import ChevronDown20 from '@andes/icons/ChevronDown20';
import { VisuallyHidden } from '@andes/visually-hidden';
import TagContent from './TagContent';
import useDropdown from '../hooks/useDropdown';
import { MODIFIER_ERROR, MENU_BOUNDARIES } from '../constants/layout';
import { WARNING_LABEL } from '../constants/warnings';
import computeSearchProps from '../utils/computeSearchProps';
import computeValueType from '../utils/computeValueType';
import { namespace, formNamespace, triggerNamespace, floatingMenuNamespace } from '../constants';
import { useThemeContext } from '@andes/themes';
import { getDataAttributes } from '../utils/getDataAttributes';

/**
 * @typedef {Object} DropdownFormInternalProps
 * @prop {string} [dataAttributesComponent]
 */

/**
 * @typedef {import('../..').DropdownForm} DropdownFormPublicProps
 */

/**
 * @typedef {DropdownFormPublicProps & DropdownFormInternalProps} DropdownFormProps
 */

/** @type {React.FunctionComponent<React.ComponentProps<DropdownFormProps>>} */
const DropdownForm = ({ ref, ...props }) => {
  const {
    allowUnselect = false,
    children,
    className,
    defaultOpen = false,
    defaultValue: defaultValueProp,
    disabled = false,
    id: idProp,
    label = '',
    menuAlignment = 'center',
    menuMaxHeight,
    modifier,
    multiple = false,
    open,
    placeholder = '',
    renderCustomTrigger,
    renderMultipleTriggerContent,
    search = false,
    srLabel,
    value: valueProp,
    dataAttributesComponent,
  } = props;

  const id = useId(idProp);
  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const dataAttributes = getDataAttributes('form', { disabled, modifier }, dataAttributesComponent);

  /** @type {React.RefObject<HTMLDivElement | null>} */
  const ownContainerRef = useRef(null);

  /** @type {React.RefObject<HTMLDivElement | null>} */
  const containerRef = /** @type {React.RefObject<HTMLDivElement>} */(ref) || ownContainerRef;

  const searchConfig = computeSearchProps({ search });

  const { value, defaultValue } = computeValueType({ valueProp, defaultValueProp });

  const defaultProps = { disabled, multiple, menuAlignment, search };

  const {
    menuProps,
    isMenuVisible,
    currentDisplayValues,
    currentValues,
  } = useDropdown(containerRef, { ...props, ...defaultProps, id, searchConfig, value, defaultValue });

  const currentDisplayValuesHasItems = Array.isArray(currentDisplayValues) && currentDisplayValues.length > 0;

  /**
   * Single selection
   * @param {(content: React.ReactNode) => void} [updateTriggerContent]
   * @returns {React.ReactNode}
   */
  const getTriggerContent = (updateTriggerContent) => {
    let newTriggerContent = null;

    if (!Array.isArray(currentDisplayValues) && currentDisplayValues) {
      newTriggerContent = (
        <span
          className={`${namespace}__display-values`}
          id={`${id}-display-values`}
          {...dataAttributes?.value}
        >
          {currentDisplayValues}
        </span>
      );
    } else if (currentDisplayValuesHasItems) {
      newTriggerContent = (
        <span
          className={`${namespace}__display-values`}
          id={`${id}-display-values`}
          {...dataAttributes?.value}
        >
          {[currentDisplayValues.join()]}
        </span>
      );
    } else if (placeholder) {
      newTriggerContent = (
        <span className={`${namespace}__placeholder`} id={`${id}-display-values`} {...dataAttributes?.placeholder}>
          {placeholder}
        </span>
      );
    }

    if (typeof renderCustomTrigger === 'function') {
      newTriggerContent = (
        <span
          className={`${namespace}__display-values`}
          id={`${id}-display-values`}
          {...dataAttributes?.value}
        >
          {renderCustomTrigger(currentDisplayValues, currentValues)}
        </span>
      );
    }

    if (typeof updateTriggerContent === 'function') updateTriggerContent(newTriggerContent);

    return newTriggerContent;
  };

  /**
   * Multiple selection
   * @param {(content: React.ReactElement) => void} [updateTriggerContent]
   * @returns {React.ReactElement}
   */
  const getTagTriggerContent = (updateTriggerContent) => {
    const newTagContent = (
      <TagContent
        currentDisplayValues={currentDisplayValues}
        currentValues={currentValues}
        disabled={disabled}
        namespace={namespace}
        containerRef={containerRef}
        onSelectionChange={menuProps.onChange}
        id={id}
        renderMultipleTriggerContent={renderMultipleTriggerContent}
      />
    );

    if (typeof updateTriggerContent === 'function') updateTriggerContent(newTagContent);

    return newTagContent;
  };

  const [triggerContent, setTriggerContent] = useState(getTriggerContent());
  const [tagTriggerContent, setTagTriggerContent] = useState(getTagTriggerContent());

  useEffect(() => {
    if (!multiple || !currentDisplayValuesHasItems) {
      getTriggerContent(setTriggerContent);
    }

    if (multiple) {
      getTagTriggerContent(setTagTriggerContent);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentDisplayValues, disabled]);

  const getMessage = () => {
    const { helper } = props;

    if (helper && !disabled) {
      return (
        <Helper
          // @ts-expect-error: Internal prop
          andesDataAttributes={dataAttributes?.helper}
          className={`${namespace}__helper`}
          id={`${id}-helper`}
          modifier={modifier === MODIFIER_ERROR ? MODIFIER_ERROR : undefined}
        >
          {helper}
        </Helper>
      );
    }

    return null;
  };

  const getMenuWidth = () => {
    const main = containerRef.current;
    const trigger = main?.getElementsByClassName(triggerNamespace)[0];

    if (trigger) {
      return { width: trigger.clientWidth + MENU_BOUNDARIES };
    }

    return undefined;
  };

  const containerClassNames = classNames(namespace, `${namespace}--form`, formNamespace, className, {
    [`${namespace}--open`]: isMenuVisible,
    [`${namespace}--multiple`]: multiple,
    [`${namespace}--bottom`]: menuAlignment === 'bottom' || search,
    [`${namespace}--error`]: modifier === MODIFIER_ERROR,
    [`${namespace}--disabled`]: disabled,
  }, getThemedComponentClasses?.('dropdown'));

  const trigger = (
    // eslint-disable-next-line jsx-a11y/role-supports-aria-props
    <button
      aria-labelledby={`${srLabel ? `${id}-sr-label` : `${id}-label`} ${id}-display-values`}
      aria-describedby={getMessage() ? `${id}-helper` : undefined}
      aria-invalid={modifier === MODIFIER_ERROR}
      className={triggerNamespace}
      disabled={disabled}
      type="button"
      id={`${id}-trigger`}
      {...dataAttributes?.trigger}
    >
      <span className={`${triggerNamespace}-content`} {...dataAttributes?.triggerContent}>
        {((!multiple || !currentDisplayValuesHasItems) && triggerContent) || (
          <span className={`${namespace}__display-values`} {...dataAttributes?.value} />
        )}
        <div className={`${namespace}__chevron`} aria-hidden {...dataAttributes?.chevron}>
          <ChevronDown20 color="currentColor" />
        </div>
      </span>
    </button>
  );

  const { menuOffsetCalculated, menuOffsetY, ...other } = menuProps;

  return (
    <div
      className={containerClassNames}
      ref={containerRef}
      id={menuProps.id}
      {...themeHash}
      {...dataAttributes?.container}
    >
      {srLabel && (
        <VisuallyHidden id={`${id}-sr-label`}>{srLabel}</VisuallyHidden>
      )}
      {label && (
        <span
          id={`${id}-label`}
          className={`${namespace}__label`}
          aria-hidden
          {...dataAttributes?.label}
        >
          {label}
        </span>
      )}
      <div className={`${namespace}__trigger-wrapper`}>
        <FloatingMenu
          {...other}
          {...getMenuWidth()}
          search={searchConfig}
          srLabel={srLabel || label}
          allowUnselect={allowUnselect}
          className={menuOffsetCalculated ? `${floatingMenuNamespace}--show` : ''}
          defaultOpen={defaultOpen}
          defaultValue={defaultValue}
          id={`${menuProps.id}-menu`}
          menuMaxHeight={menuMaxHeight}
          multiple={multiple}
          // @ts-expect-error
          // Offset prop doesn't exist in FloatingMenu, it's a popper prop
          offset={[0, menuOffsetY]}
          open={open}
          trigger={trigger}
          type="select"
          value={multiple ? currentValues : value}
        >
          {children}
        </FloatingMenu>
        {multiple && tagTriggerContent}
      </div>
      {getMessage()}
    </div>
  );
};

/** @type {import('prop-types').Validator<string>} */
const checkLabelProp = ({ srLabel, label }, propName, componentName) => {
  PropTypes.checkPropTypes({ srLabel: PropTypes.string }, { srLabel }, propName, componentName);
  PropTypes.checkPropTypes({ label: PropTypes.string }, { label }, propName, componentName);

  return !srLabel && !label ? new Error(WARNING_LABEL) : null;
};

DropdownForm.propTypes = {
  allowUnselect: PropTypes.bool,
  children: PropTypes.oneOfType([PropTypes.element.isRequired, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
  className: PropTypes.string,
  defaultOpen: PropTypes.bool,
  defaultValue: PropTypes.oneOfType([PropTypes.string, PropTypes.arrayOf(PropTypes.string.isRequired)]),
  disabled: PropTypes.bool,
  helper: PropTypes.node,
  id: PropTypes.string,
  label: checkLabelProp,
  menuAlignment: PropTypes.oneOf(['bottom', 'center']),
  menuMaxHeight: PropTypes.number,
  modifier: PropTypes.oneOf(['error', 'readonly']),
  multiple: PropTypes.bool,
  onChange: PropTypes.func,
  onClose: PropTypes.func,
  onOpen: PropTypes.func,
  open: PropTypes.bool,
  placeholder: PropTypes.string,
  search: PropTypes.oneOfType([PropTypes.bool, PropTypes.shape({
    defaultValue: PropTypes.string,
    filterCondition: PropTypes.func,
    onChange: PropTypes.func,
    placeholder: PropTypes.string,
  })]),
  srLabel: checkLabelProp,
  renderCustomTrigger: PropTypes.func,
  renderMultipleTriggerContent: PropTypes.func,
  value: PropTypes.oneOfType([PropTypes.string.isRequired, PropTypes.arrayOf(PropTypes.string.isRequired)]),
};

export default DropdownForm;
