export const namespace = 'andes-helper';

export const MODIFIER_CAUTION = 'caution';
export const MODIFIER_ERROR = 'error';

export const COLOR_CAUTION = 'caution';
export const COLOR_NEGATIVE = 'negative';

export const MODIFIER = /** @type {const} */ ([MODIFIER_CAUTION, MODIFIER_ERROR]);

export const COLOR = {
  [`${MODIFIER_CAUTION}`]: /** @type {import('@andes/badge').BadgeColors} */ (COLOR_CAUTION),
  [`${MODIFIER_ERROR}`]: /** @type {import('@andes/badge').BadgeColors} */ (COLOR_NEGATIVE),
};
